class Solution:
    def countGoodNodes(self, edges):
        n = len(edges) + 1
        graph = {i: [] for i in range(n)}
        for a, b in edges:
            graph[a].append(b)
            graph[b].append(a)
        import sys
        sys.setrecursionlimit(10000)
        memo = {}

        def size(node, parent):
            if (node, parent) in memo:
                return memo[(node, parent)]
            total = 1
            for nb in graph[node]:
                if nb != parent:
                    total += size(nb, node)
            memo[(node, parent)] = total
            return total

        def parent_of(root):
            par = [-1] * n
            order = [root]
            seen = [False] * n
            seen[root] = True
            stack = [root]
            while stack:
                u = stack.pop()
                for v in graph[u]:
                    if not seen[v]:
                        seen[v] = True
                        par[v] = u
                        stack.append(v)
            return par

        par = parent_of(0)
        good = 0
        for node in range(n):
            child_sizes = [size(c, node) for c in graph[node] if par[c] == node]
            if len(set(child_sizes)) <= 1:
                good += 1
        return good

