class Solution:
    def countGoodNodes(self, edges):
        n = len(edges) + 1
        graph = [[] for _ in range(n)]
        for a, b in edges:
            graph[a].append(b)
            graph[b].append(a)
        parent = [-1] * n
        visited = [False] * n
        visited[0] = True
        order = []
        stack = [0]
        while stack:
            node = stack.pop()
            order.append(node)
            for nb in graph[node]:
                if not visited[nb]:
                    visited[nb] = True
                    parent[nb] = node
                    stack.append(nb)
        size = [1] * n
        for node in reversed(order):
            p = parent[node]
            if p != -1:
                size[p] += size[node]
        good = 0
        for node in range(n):
            child_sizes = [size[c] for c in graph[node] if parent[c] == node]
            if len(set(child_sizes)) <= 1:
                good += 1
        return good

