var countGoodNodes = function(edges) {
    const n = edges.length + 1;
    const graph = Array.from({ length: n }, () => []);
    for (const [a, b] of edges) {
        graph[a].push(b);
        graph[b].push(a);
    }
    const parent = new Array(n).fill(-1);
    const visited = new Array(n).fill(false);
    visited[0] = true;
    const order = [];
    const stack = [0];
    while (stack.length) {
        const node = stack.pop();
        order.push(node);
        for (const nb of graph[node]) {
            if (!visited[nb]) {
                visited[nb] = true;
                parent[nb] = node;
                stack.push(nb);
            }
        }
    }
    const size = new Array(n).fill(1);
    for (let i = order.length - 1; i >= 0; i--) {
        const node = order[i];
        const p = parent[node];
        if (p !== -1) size[p] += size[node];
    }
    let good = 0;
    for (let node = 0; node < n; node++) {
        const childSizes = new Set();
        for (const c of graph[node]) {
            if (parent[c] === node) childSizes.add(size[c]);
        }
        if (childSizes.size <= 1) good++;
    }
    return good;
};
